prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?gatewayDirection ?instantiate ?eventGatewayType WHERE {
  ?model a bboExt:Model .
  FILTER(CONTAINS(STR(?model), "f404135647444aedabe98bb54c000517"))
  ?def a bboExt:Definitions .
  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?def .
  ?gateway a bboExt:EventBasedGateway .
  ?gateway tai:belongsTo ?choreo .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?gatewayDirection . }
  OPTIONAL { ?gateway bboExt:instantiate ?instantiate . }
  OPTIONAL { ?gateway bboExt:eventGatewayType ?eventGatewayType . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?originalId ?normalizedId WHERE {
  ?model a bboExt:Model .
  {
    FILTER(CONTAINS(STR(?model), "f404135647444aedabe98bb54c000517"))
  } UNION {
    ?model tai:originalId "f404135647444aedabe98bb54c000517" .
  } UNION {
    ?model tai:normalizedId "f404135647444aedabe98bb54c000517" .
  }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
}
LIMIT 10

